def format_elapsed_time(seconds: float) -> str:
    """把秒数格式化为适合日志阅读的用时文本。"""
    try:
        total = max(0, int(round(float(seconds))))
    except Exception:
        total = 0
    hours, rem = divmod(total, 3600)
    minutes, secs = divmod(rem, 60)
    if hours:
        return f"{hours}小时{minutes}分{secs}秒"
    if minutes:
        return f"{minutes}分{secs}秒"
    return f"{secs}秒"


def save_timing_summary(out_dir: str, title: str, records: list, overall_seconds: float, logger=None) -> str:
    """保存按章运行计时摘要，便于复盘每个章节总耗时。"""
    os.makedirs(out_dir, exist_ok=True)
    summary_path = os.path.join(out_dir, "运行计时摘要.txt")
    lines = []
    lines.append(f"任务：{title}")
    lines.append(f"生成时间：{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    lines.append(f"总用时：{format_elapsed_time(overall_seconds)}")
    lines.append("")
    lines.append("章节用时：")
    for rec in records:
        lines.append(
            f"{rec.get('index', '')}. {rec.get('title', '')} | "
            f"状态：{rec.get('status', '完成')} | "
            f"用时：{format_elapsed_time(rec.get('seconds', 0))}"
        )
    with open(summary_path, "w", encoding="utf-8") as f:
        f.write("\n".join(lines) + "\n")
    if logger:
        logger(f"📝 计时摘要已保存：{summary_path}")
    return summary_path


