def decode_text_bytes(raw: bytes, default: str = "") -> str:
    """多编码兜底解码，优先保证中文 Markdown / OCR 文本不乱码。"""
    if raw is None:
        return default
    if isinstance(raw, str):
        return raw
    if not isinstance(raw, (bytes, bytearray)):
        try:
            return str(raw)
        except Exception:
            return default
    data = bytes(raw)
    if not data:
        return default
    # 先处理 BOM / 常见 Unicode 编码，再尝试中文环境常见编码。
    encodings = [
        "utf-8-sig", "utf-8", "gb18030", "gbk", "big5", "utf-16", "utf-16-le", "utf-16-be", "cp1252", "latin-1"
    ]
    best_text = None
    best_score = -10**9
    for enc in encodings:
        try:
            txt = data.decode(enc, errors="replace")
        except Exception:
            continue
        # 评分：少替换字符、少控制字符、有中文/英文可读字符、不过度乱码。
        replacement_count = txt.count("�")
        control_count = sum(1 for ch in txt if ord(ch) < 32 and ch not in "\n\r\t")
        cn_count = len(re.findall(r"[\u4e00-\u9fff]", txt))
        ascii_word_count = len(re.findall(r"[A-Za-z]{2,}", txt))
        printable_count = sum(1 for ch in txt if ch.isprintable() or ch in "\n\r\t")
        score = cn_count * 3 + ascii_word_count + printable_count * 0.01 - replacement_count * 80 - control_count * 10
        if score > best_score:
            best_score = score
            best_text = txt
        # UTF-8 无替换通常已经最可信。
        if enc in {"utf-8-sig", "utf-8"} and replacement_count == 0 and txt.strip():
            return txt
    return best_text if best_text is not None else default


def read_text_file(path: str, default: str = "") -> str:
    """统一文本读取，自动尝试 utf-8 / gb18030 / gbk / big5 等多种编码。"""
    try:
        with open(path, "rb") as f:
            return decode_text_bytes(f.read(), default=default)
    except Exception:
        return default


def write_text_file(path: str, text: str) -> None:
    """统一文本写入，自动创建父目录。"""
    folder = os.path.dirname(os.path.abspath(path))
    if folder:
        os.makedirs(folder, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        f.write(str(text or ""))


def safe_remove_file(path: str, logger=None, *, retries: int | None = None, sleep_seconds: float | None = None) -> bool:
    """Windows 友好的安全删除：外部 PDF 解析器短暂占用文件时，不让流程崩溃。"""
    if not path or not os.path.exists(path):
        return True
    retries = WINDOWS_FILE_CLEANUP_RETRIES if retries is None else max(1, int(retries))
    sleep_seconds = WINDOWS_FILE_CLEANUP_SLEEP if sleep_seconds is None else max(0.05, float(sleep_seconds))
    last_err = None
    for i in range(retries):
        try:
            os.remove(path)
            return True
        except PermissionError as e:
            last_err = e
            time.sleep(min(5.0, sleep_seconds * (i + 1)))
        except FileNotFoundError:
            return True
        except Exception as e:
            last_err = e
            time.sleep(min(5.0, sleep_seconds * (i + 1)))
    if logger:
        logger(f"⚠️ 临时文件暂时无法删除，可能仍被外部解析器占用；已跳过，不影响后续流程：{path}；原因：{str(last_err)[:120]}")
    return False


def safe_rmtree(path: str, logger=None, *, retries: int | None = None, sleep_seconds: float | None = None) -> bool:
    """Windows 友好的目录删除：PermissionError/WinError 32 时重试，最终失败也不抛出。"""
    if not path or not os.path.exists(path):
        return True
    retries = WINDOWS_FILE_CLEANUP_RETRIES if retries is None else max(1, int(retries))
    sleep_seconds = WINDOWS_FILE_CLEANUP_SLEEP if sleep_seconds is None else max(0.05, float(sleep_seconds))
    last_err = None

    def _onerror(func, p, exc_info):
        try:
            os.chmod(p, 0o700)
            func(p)
        except Exception:
            pass

    for i in range(retries):
        try:
            shutil.rmtree(path, onerror=_onerror)
            return True
        except PermissionError as e:
            last_err = e
            time.sleep(min(5.0, sleep_seconds * (i + 1)))
        except FileNotFoundError:
            return True
        except Exception as e:
            last_err = e
            time.sleep(min(5.0, sleep_seconds * (i + 1)))
    if logger:
        logger(f"⚠️ 临时目录暂时无法清理，可能有文件句柄未释放；已跳过，不影响后续流程：{path}；原因：{str(last_err)[:120]}")
    return False



def ascii_safe_filename(text: str, max_len: int = 80, fallback: str = "upload.pdf") -> str:
    """生成只含 ASCII 的上传文件名，避免 Windows 中文路径/文件名进入 multipart header 后触发 ascii codec 错误。"""
    raw = str(text or "").strip() or fallback
    stem, ext = os.path.splitext(raw)
    if not ext:
        ext = os.path.splitext(fallback)[1] or ".pdf"
    # 去除重音并转 ASCII；中文会被丢弃，因此再兜底。
    stem_ascii = unicodedata.normalize("NFKD", stem).encode("ascii", "ignore").decode("ascii", "ignore")
    stem_ascii = re.sub(r"[^A-Za-z0-9._-]+", "_", stem_ascii).strip("._-")
    if not stem_ascii:
        stem_ascii = os.path.splitext(fallback)[0] or "upload"
    ext_ascii = re.sub(r"[^A-Za-z0-9.]", "", ext) or ".pdf"
    if not ext_ascii.startswith("."):
        ext_ascii = "." + ext_ascii
    name = (stem_ascii[:max_len].strip("._-") or "upload") + ext_ascii.lower()
    try:
        name.encode("ascii")
    except Exception:
        name = fallback
    return name


class AsciiUploadCopy:
    """为云端文件上传创建 ASCII 文件名副本；退出时安全清理。"""
    def __init__(self, source_path: str, suffix: str = ".pdf", logger=None):
        self.source_path = source_path
        self.suffix = suffix if suffix.startswith(".") else "." + suffix
        self.logger = logger
        self.temp_dir = ""
        self.path = source_path
        self.upload_name = ascii_safe_filename(os.path.basename(source_path), fallback="chapter_upload" + self.suffix)

    def __enter__(self):
        # 只要原始路径或文件名包含非 ASCII，就复制到 ASCII-only 临时路径；否则也返回安全上传名给 SDK。
        try:
            str(self.source_path).encode("ascii")
            os.path.basename(self.source_path).encode("ascii")
            self.path = self.source_path
            self.upload_name = ascii_safe_filename(os.path.basename(self.source_path), fallback="chapter_upload" + self.suffix)
            return self
        except Exception:
            pass
        self.temp_dir = tempfile.mkdtemp(prefix="quanlan_upload_")
        self.upload_name = "chapter_upload" + self.suffix
        self.path = os.path.join(self.temp_dir, self.upload_name)
        shutil.copy2(self.source_path, self.path)
        return self

    def __exit__(self, exc_type, exc, tb):
        if self.temp_dir:
            safe_rmtree(self.temp_dir, self.logger)
        return False


def build_utf8_subprocess_env() -> dict:
    """构造 UTF-8 子进程环境；保留给通用扩展使用，PDF 解析不再调用本地解析器。"""
    env = os.environ.copy()
    env.setdefault("PYTHONUTF8", "1")
    env.setdefault("PYTHONIOENCODING", "utf-8")
    env.setdefault("LC_ALL", "C.UTF-8")
    env.setdefault("LANG", "C.UTF-8")
    return env


def compact_instruction_prompt(prompt: str) -> str:
    """只压缩系统/任务提示词中的完全重复段落与多余空白；不处理参考原文，避免损失内容。"""
    raw = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    paragraphs = re.split(r"\n{2,}", raw)
    seen = set()
    kept = []
    for para in paragraphs:
        cleaned_lines = [re.sub(r"[ \t]+", " ", ln).strip() for ln in para.split("\n")]
        cleaned = "\n".join([ln for ln in cleaned_lines if ln]).strip()
        if not cleaned:
            continue
        key = re.sub(r"\s+", " ", cleaned)
        if key in seen:
            continue
        seen.add(key)
        kept.append(cleaned)
    return "\n\n".join(kept).strip()


def get_voiceover_text_path(script_path: str) -> str:
    """最终口播台词路径。

    精简模式下，主脚本文件本身就是最终口播台词，避免同一内容同时保存
    “导读脚本最终版.txt”和“口播台词最终版.txt”两个副本。
    """
    if unified_intermediate_files_enabled():
        return script_path
    base, _ = os.path.splitext(script_path)
    return base + "_11_口播台词_逐句锁定_最终版.txt"


