def compute_image_prompt_api_text(prompt_name: str, prompt_text: str) -> str:
    try:
        return prepare_image_prompt_for_api(prompt_text, prompt_name=f"{prompt_name}.png" if prompt_name and not str(prompt_name).lower().endswith(".png") else str(prompt_name or ""), logger=None)
    except Exception:
        return str(prompt_text or "")


def compute_image_prompt_hash(prompt_name: str, prompt_text: str) -> str:
    import hashlib
    api_text = compute_image_prompt_api_text(prompt_name, prompt_text)
    return hashlib.sha256(api_text.encode("utf-8", errors="ignore")).hexdigest()


def write_image_prompt_sidecars(image_path: str, prompt_name: str, prompt_text: str, logger=None) -> None:
    try:
        api_text = compute_image_prompt_api_text(prompt_name, prompt_text)
        import hashlib
        digest = hashlib.sha256(api_text.encode("utf-8", errors="ignore")).hexdigest()
        if save_image_api_prompt_sidecars_enabled():
            write_text_file(get_image_prompt_api_text_path(image_path), api_text.strip() + "\n")
        write_text_file(get_image_prompt_hash_path(image_path), digest + "\n")
    except Exception as e:
        if logger:
            logger(f"⚠️ 写入配图 Prompt 指纹失败：{os.path.basename(str(image_path or ''))}；{str(e)[:100]}")


def image_prompt_sidecar_matches(image_path: str, prompt_name: str, prompt_text: str) -> bool:
    try:
        hp = get_image_prompt_hash_path(image_path)
        if not is_nonempty_file(hp, min_bytes=16):
            return False
        saved = read_text_file(hp).strip().split()[0]
        return bool(saved and saved == compute_image_prompt_hash(prompt_name, prompt_text))
    except Exception:
        return False


