def clean_video_description_text(text: str, max_chars: int = 260) -> str:
    """清理视频简介：只保留正文，不混入标题、关注语、绘图提示词或代码围栏。"""
    raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    raw = re.sub(r"```[a-zA-Z0-9_-]*", "", raw)
    raw = raw.replace("```", "")
    lines = []
    for line in raw.splitlines():
        t = line.strip()
        if not t:
            continue
        t = re.sub(r"^\s*(?:视频简介|简介|发布文案|Description)\s*[：:]\s*", "", t, flags=re.I).strip()
        if not t:
            continue
        if re.match(r"^\s*(?:提示词|Prompt|Image Prompt|绘图提示词)\s*[：:]", t, flags=re.I):
            continue
        if is_visual_prompt_contamination(t):
            continue
        lines.append(t)
    text = "".join(lines).strip()
    # 视频简介不承载关注动作；关注提示统一交给尾页品牌页。
    cta_patterns = [
        r"了解更多[，,、 ]*请点击下方关注《?全澜脑科学》?公众号[。.!！]*",
        r"请点击下方关注《?全澜脑科学》?公众号[。.!！]*",
        r"关注我们[，,、 ]*",
        r"更多信息[，,、 ]*请关注《?全澜脑科学》?公众号[。.!！]*",
    ]
    for pat in cta_patterns:
        text = re.sub(pat, "", text)
    text = re.sub(r"\s+", "", text).strip(" ，,。；;：:\n\t")
    # 保守截断，避免模型输出长文；尽量在句号处结束。
    if max_chars and len(text) > max_chars:
        cut = text[:max_chars]
        last_punct = max(cut.rfind("。"), cut.rfind("！"), cut.rfind("？"), cut.rfind("；"))
        if last_punct >= 120:
            cut = cut[:last_punct + 1]
        text = cut.rstrip("，,；;：:")
        if text and text[-1] not in "。！？；":
            text += "。"
    return text + ("\n" if text else "")


def extract_video_description_from_text(text: str) -> str:
    """从模型完整输出中提取“视频简介”区块，作为无模型兜底。"""
    raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    m = re.search(r"(?is)(?:^|\n)\s*(?:【\s*)?(?:4[.、．]\s*)?视频简介(?:\s*】)?\s*[：:]?\s*(.*)$", raw)
    if not m:
        return ""
    body = m.group(1)
    # 遇到后续明显章节/提示词字段就停止。
    stop = re.search(r"(?im)^\s*(?:【|#{1,6}|Shot[_\- ]?\d+|Final\s+Shot|Page Type|Prompt|提示词|绘图提示词|检查|审校)", body)
    if stop:
        body = body[:stop.start()]
    return clean_video_description_text(body)


