def _split_author_names_for_voiceover(author_block: str) -> list[str]:
    """把作者字段拆成作者列表；仅用于口播压缩，不影响封面/首页完整作者显示。"""
    s = str(author_block or "").replace("\u00a0", " ")
    s = re.sub(r"（[^）]*）|\([^)]*\)", " ", s)
    s = re.sub(r"\b(?:authors?|edited\s+by|editor|by|written\s+by)\b\s*[：:=]?", " ", s, flags=re.I)
    s = re.sub(r"(?:作者|著者|主编|编著|合著|等著|等编|著|编)\s*$", " ", s)
    s = re.sub(r"\s+", " ", s).strip(" ，,、;；:/")
    if not s:
        return []

    s = re.sub(r"\bet\s+al\.?\b", " 等人", s, flags=re.I)
    s = re.sub(r"\s+(?:and|&|和|与|及)\s+", "、", s, flags=re.I)
    s = re.sub(r"\s*(?:;|；|、|/|\\+)\s*", "、", s)

    comma_parts = re.split(
        r"\s*,\s*(?=(?:[A-Z][A-Z.\-']*\s+){0,4}[A-Z][A-Z.\-']{2,}|(?:[A-Z][a-zA-Z'’.-]+\s+){1,4}[A-Z][a-zA-Z'’.-]+|[\u4e00-\u9fff])",
        s,
    )
    names = []
    for part in comma_parts:
        for item in re.split(r"[、]+", part):
            item = item.strip(" ，,、;；")
            if not item:
                continue
            if re.fullmatch(r"(?:等|等人|et\s*al\.?)", item, flags=re.I):
                continue
            names.append(item)

    deduped = []
    seen = set()
    for name in names:
        key = re.sub(r"[\W_]+", "", name).lower()
        if key and key not in seen:
            seen.add(key)
            deduped.append(name)
    return deduped


def _normalize_english_name_piece_for_voiceover(value: str) -> str:
    token = str(value or "").strip(" .,'’\"“”")
    if not token:
        return ""
    if re.fullmatch(r"[A-Z][A-Z'’.-]+", token):
        return token[:1].upper() + token[1:].lower()
    return token[:1].upper() + token[1:] if token.islower() else token


def _extract_first_author_short(author_block: str) -> str:
    """口播只取第一作者简名：英文取姓氏，中文保留姓名。"""
    authors = _split_author_names_for_voiceover(author_block)
    first = authors[0] if authors else str(author_block or "")
    first = re.sub(r"（[^）]*）|\([^)]*\)", " ", first)
    first = re.sub(r"\b(?:editor|edited\s+by|authors?|by|written\s+by)\b", " ", first, flags=re.I)
    first = re.sub(r"(?:作者|著者|主编|编著|合著|著|编|等人|等)", " ", first)
    first = first.strip(" ，,、;；")
    if not first:
        return ""

    cjk_match = re.search(r"[\u4e00-\u9fff]{2,6}", first)
    if cjk_match and not re.search(r"[A-Za-z]", first):
        return cjk_match.group(0)

    words = re.findall(r"[A-Za-z][A-Za-z'’.-]*", first)
    words = [w for w in words if not re.fullmatch(r"[A-Z]\.?,?", w)]
    if not words:
        return first.strip()
    return _normalize_english_name_piece_for_voiceover(words[-1])


def format_voiceover_author_credit(author_block: str) -> str:
    """口播作者格式：单作者念简名；多作者念“第一作者简名等人合著”。"""
    raw = str(author_block or "")
    first = _extract_first_author_short(raw)
    if not first:
        return ""
    authors = _split_author_names_for_voiceover(raw)
    multiple = len(authors) >= 2 or bool(re.search(r"\bet\s*al\.?\b|等人|等著|合著", raw, flags=re.I))
    return f"{first}等人合著" if multiple else first



def simplify_voiceover_book_title(book_title: str) -> str:
    """台词开头只使用简要中文书名，避免念英文长题名、版本、出版社和 ISBN。"""
    raw = str(book_title or "").strip()
    if not raw:
        return "这本书"
    # 特例：Principles of Neural Science / 神经科学原理，台词只念简名。
    if re.search(r"principles\s+of\s+neural\s+science|神经科学原理", raw, flags=re.I):
        return "神经科学原理"
    text = re.sub(r"（[^）]*(?:版|edition|isbn|出版|出版社)[^）]*）|\([^)]*(?:版|edition|isbn|出版|出版社)[^)]*\)", "", raw, flags=re.I)
    text = re.sub(r"[,，;；:].*$", "", text).strip()
    text = re.sub(r"第[一二三四五六七八九十0-9]+版|\b\d+(?:st|nd|rd|th)?\s+edition\b|isbn(?:-?13)?\s*[:：]?\s*\d[\d-]*", "", text, flags=re.I).strip()
    # 保留中文主标题；没有中文时保留短英文主标题。
    m = re.search(r"[\u4e00-\u9fff][\u4e00-\u9fffA-Za-z0-9·：:《》\-— ]{1,40}", text)
    if m:
        return m.group(0).strip("《》 ：:-—") or "这本书"
    words = re.findall(r"[A-Za-z][A-Za-z'’.-]*", text)
    if words:
        return " ".join(words[:6])
    return text[:40] or "这本书"

def format_voiceover_book_intro(book_title: str, author_block: str = "", chapter_number: str = "") -> str:
    """生成口播章节引入句前缀：在由Kandel等人合著《神经科学原理》的第32章中。

    - 书名只保留中文简名，避免英文长书名、editor、出版社、ISBN 进入旁白。
    - 多作者统一写成“首位作者简名等人合著”，不在中文词组中间插空格。
    - 无作者时退回“在《书名》的第X章中”。
    """
    book = simplify_voiceover_book_title(book_title)
    chapter = str(chapter_number or "").strip()
    chapter = re.sub(r"^第\s*", "", chapter)
    chapter = re.sub(r"\s*章$", "", chapter)
    chapter_part = f"第{chapter}章" if chapter else "本章"
    credit = format_voiceover_author_credit(author_block)
    if credit:
        return f"在由{credit}《{book}》的{chapter_part}中"
    return f"在《{book}》的{chapter_part}中"


def simplify_bibliographic_voiceover(text: str) -> str:
    """把口播中的书目信息压缩成：由作者合著《中文简名》的第X章。"""
    raw = str(text or "")
    chapter_re = r"[一二三四五六七八九十百千万零〇两\d]{1,12}"

    def make_intro(book: str, authors: str = "", chapter: str = "") -> str:
        return format_voiceover_book_intro(book, authors, chapter)

    pat = re.compile(
        rf"在由(?P<authors>[^。！？\n]{{1,220}}?)(?:主编|编著|著|合著)[^。！？\n]{{0,260}}?《(?P<book>[^》]{{1,260}})》[^。！？\n]{{0,260}}?第(?P<chapter>{chapter_re})章中"
    )

    def repl_by(m):
        return make_intro(m.group('book'), m.group('authors'), m.group('chapter'))

    raw = pat.sub(repl_by, raw)

    def repl_inline(m):
        book, authors, chapter = m.group(1), m.group(2), m.group(3)
        return make_intro(book, authors, chapter)

    # 形如：在《英文长书名...》Kandel等人合著的第32章中
    raw = re.sub(
        rf"在《([^》]{{1,320}})》\s*([^。！？\n]{{1,180}}?(?:等人合著|等著|合著|主编|编著|著|编))(?:的)?第({chapter_re})章中",
        repl_inline,
        raw,
        flags=re.I,
    )

    # 形如：在《英文长书名...》作者 Kandel 等人的第32章中
    raw = re.sub(
        rf"在《([^》]{{1,320}})》\s*作者\s*([^。！？\n]{{1,260}}?)(?:的)?第({chapter_re})章中",
        repl_inline,
        raw,
        flags=re.I,
    )

    # 书名中混入 ISBN / 出版社 / editor 等书目噪声，但没有可靠作者时，至少保留中文简名与章节号。
    def repl_no_author(m):
        return make_intro(m.group(1), "", m.group(2))

    raw = re.sub(
        rf"在《([^》]{{1,320}})》[^。！？\n]{{0,220}}?(?:ISBN(?:-?13)?[:：]?\s*\d[\d-]*|isbn13\s*\d[\d-]*|editor|New York|McGraw|纽约出版|于\d{{4}}年|第六版|第[一二三四五六七八九十0-9]+版)[^。！？\n]{{0,220}}?第({chapter_re})章中",
        repl_no_author,
        raw,
        flags=re.I,
    )

    raw = re.sub(rf"在《([^》]{{1,320}})》第({chapter_re})章中", lambda m: make_intro(m.group(1), "", m.group(2)), raw)
    raw = re.sub(r"作者([^，。；；\n]{1,80})等的的", r"作者\1等的", raw)
    raw = re.sub(r"([^，。；；\n]{1,80})等人合著的的", r"\1等人合著的", raw)
    raw = re.sub(r"由\s+([A-Za-z])", r"由\1", raw)
    raw = re.sub(r"([A-Za-z])\s+等人合著", r"\1等人合著", raw)
    return raw


