LRC_IMAGE_MARKER_RE = re.compile(r"【\s*(?:图\s*\d+|A1|A2|A01|A02|B\d{1,3}|C)\s*】", re.I)
LRC_IMAGE_MARKER_CAPTURE_RE = re.compile(r"【\s*(图\s*\d+|A1|A2|A01|A02|B\d{1,3}|C)\s*】", re.I)


def lrc_image_label_for_index(image_no: int, total_images: int = 0, page_type: str = "", prompt_name: str = "") -> str:
    """把内部图片顺序号转换为公开 LRC 锚点：A1/A2/B01.../C。"""
    try:
        n = int(image_no or 0)
    except Exception:
        n = 0
    try:
        total = int(total_images or 0)
    except Exception:
        total = 0
    combined = f"{prompt_name or ''}\n{page_type or ''}"
    if re.search(r"\bA01\b|Bilibili\s*Cover|B站封面|哔哩哔哩封面", combined, flags=re.I) or n == 3:
        return "A01"
    if re.search(r"\bA02\b|Bilibili\s*Home|B站首页|哔哩哔哩首页", combined, flags=re.I) or n == 4:
        return "A02"
    if re.search(r"\bA1\b|Video\s*Cover|WeChat\s*Cover|微信封面|封面", combined, flags=re.I) or n == 1:
        return "A1"
    if re.search(r"\bA2\b|Home\s*Page|WeChat\s*Home|微信首页|首页", combined, flags=re.I) or n == 2:
        return "A2"
    if re.search(r"\bC\b|Brand\s*Page|Final|Ending|品牌|结尾|尾页", combined, flags=re.I) or (total and n == total):
        return "C"
    if n > 4:
        return f"B{max(1, n - 4):02d}"
    return ""


def lrc_image_index_for_label(label: str, total_images: int = 0) -> int:
    """把 A1/A2/B01/C 或旧图N标签转换回内部图片顺序号。"""
    raw = re.sub(r"\s+", "", str(label or "")).upper()
    raw = raw.strip("【】")
    m = re.match(r"图0*(\d+)$", raw, flags=re.I)
    if m:
        return int(m.group(1))
    if raw == "A1":
        return 1
    if raw == "A2":
        return 2
    if raw == "A01":
        return 3
    if raw == "A02":
        return 4
    m = re.match(r"B0*(\d+)$", raw)
    if m:
        return int(m.group(1)) + 4
    if raw == "C":
        try:
            return int(total_images or 0) or 9999
        except Exception:
            return 9999
    return 0


def normalize_lrc_marker_label(label: str, total_images: int = 0) -> str:
    """兼容旧【图N】并统一成 A1/A2/B01/C。"""
    n = lrc_image_index_for_label(label, total_images=total_images)
    if not n:
        return ""
    return lrc_image_label_for_index(n, total_images=total_images)


def lrc_image_label_sort_key(label: str, total_images: int = 0) -> int:
    return lrc_image_index_for_label(label, total_images=total_images)


def normalize_lrc_markers_in_text(text: str, total_images: int = 0) -> str:
    """把 LRC 里的旧数字图号改为 A1/A2/B01/C；A1 封面不生成台词锚点。"""
    def repl(m):
        label = normalize_lrc_marker_label(m.group(1), total_images=total_images)
        if not label or label in {"A1", "A01", "A02"}:
            return ""
        return f"【{label}】"
    return LRC_IMAGE_MARKER_CAPTURE_RE.sub(repl, str(text or ""))


def split_lrc_marker_and_voiceover_text(text: str, total_images: int = 0):
    """最终导出 .lrc 时使用：配图锚点独占一行，台词正文独占另一行。

    内部台词文件仍允许“【B01】台词”这种同一行绑定，便于逐句润色校验；
    但写入 LRC 时必须拆成：
    [00:00.00]【B01】
    [00:00.00]对应台词
    """
    s = normalize_lrc_markers_in_text(str(text or "").strip(), total_images=total_images).strip()
    if not s:
        return [], ""

    markers = []

    def repl(m):
        label = normalize_lrc_marker_label(m.group(1), total_images=total_images)
        if label and label != "A1":
            marker = f"【{label}】"
            if marker not in markers:
                markers.append(marker)
        return " "

    voiceover = LRC_IMAGE_MARKER_CAPTURE_RE.sub(repl, s)
    voiceover = re.sub(r"\s+", " ", voiceover).strip()
    return markers, voiceover


def get_lrc_image_marker_map_path(script_path: str) -> str:
    """保存 LRC 配图锚点与台词首句的对应表，便于复盘。"""
    base, _ = os.path.splitext(script_path)
    return base + "_13_LRC配图ABC映射表.txt"


def extract_lrc_image_marker_lines(voiceover_text: str) -> list:
    """从带【A2】/【B01】/【C】等锚点的台词中提取配图-台词对应行。"""
    rows = []
    for raw in str(voiceover_text or "").splitlines():
        line = normalize_lrc_markers_in_text(raw).strip()
        if not line:
            continue
        ms = LRC_IMAGE_MARKER_CAPTURE_RE.findall(line)
        if not ms:
            continue
        clean = strip_lrc_image_markers(line)
        for label in ms:
            norm = normalize_lrc_marker_label(label)
            if norm and norm != "A1":
                rows.append((norm, clean))
    rows.sort(key=lambda x: lrc_image_label_sort_key(x[0]))
    return rows


def write_lrc_image_marker_map(script_path: str, voiceover_text: str) -> str:
    """记录配图锚点-台词关系。

    精简模式下不再单独落盘映射表，因为同样的锚点已经内嵌在最终台词和 LRC 中；
    需要排查时可设置 QUANLAN_UNIFIED_INTERMEDIATE_FILES=0 恢复旧映射表。
    """
    if unified_intermediate_files_enabled():
        return ""
    rows = extract_lrc_image_marker_lines(voiceover_text)
    path = get_lrc_image_marker_map_path(script_path)
    if not rows:
        write_text_file(path, "未识别到 LRC 配图锚点。\n")
        return path
    lines = ["LRC 配图台词对应表", "说明：LRC 锚点使用 A2/B01/B02.../C 对应配图；A1 封面页不生成台词锚点；最终 .lrc 中锚点独占一行，台词正文另起一行。", ""]
    for label, text in rows:
        lines.append(f"{label}: {text}")
    write_text_file(path, "\n".join(lines).rstrip() + "\n")
    return path


def _looks_like_image_prompt_source_text(text: str) -> bool:
    raw = str(text or "")[:20000]
    if not raw.strip():
        return False
    # 最终绘图提示词文件、图文一一对应脚本、网页手动绘图索引都应命中这些结构信号。
    signals = [
        r"手动绘图使用说明",
        r"逐图对应",
        r"台词驱动",
        r"Source\s+Prompt\s+Name\s*:",
        r"Page\s+Type\s*:",
        r"A1[_\s-]*(?:封面|cover)",
        r"A2[_\s-]*(?:首页|home)",
        r"VOICEOVER-DRIVEN\s+IMAGE\s+BRIEF",
        r"Prompt\s*:",
    ]
    hit = sum(1 for pat in signals if re.search(pat, raw, flags=re.I))
    return hit >= 2



def _find_nearby_image_prompt_source_path(script_path: str) -> str:
    """按内容查找同章节目录里的绘图提示词文件，兼容 ZIP/Windows 环境把中文文件名转成 #Uxxxx。"""
    try:
        ch_dir = os.path.dirname(os.path.abspath(str(script_path or "")))
        if not ch_dir or not os.path.isdir(ch_dir):
            return ""
        candidates = []
        for name in os.listdir(ch_dir):
            if not str(name).lower().endswith('.txt'):
                continue
            path = os.path.join(ch_dir, name)
            if not is_nonempty_file(path, min_bytes=50):
                continue
            try:
                if os.path.getsize(path) > 800000:
                    continue
            except Exception:
                pass
            txt = _read_text_if_exists(path, max_chars=20000) if '_read_text_if_exists' in globals() else read_text_file(path)[:20000]
            if not _looks_like_image_prompt_source_text(txt):
                continue
            low = name.lower()
            score = 0
            if "_12_" in low or "#u7ed8#u56fe" in low or "绘图" in name:
                score += 40
            if "逐图" in name or "#u9010#u56fe" in low:
                score += 20
            if "台词驱动" in name or "#u53f0#u8bcd" in low:
                score += 20
            if "_08_" in low or "_09_" in low:
                score += 8
            if "最终" in name or "#u6700#u7ec8" in low:
                score += 5
            candidates.append((-score, name, path))
        if not candidates:
            return ""
        candidates.sort(key=lambda x: (x[0], x[1]))
        return candidates[0][2]
    except Exception:
        return ""



def get_preferred_prompt_source_path(script_path: str) -> str:
    """配图优先读取独立绘图提示词文件；若中文文件名被转义，则按内容自动查找。"""
    prompt_path = get_image_prompt_text_path(script_path)
    if is_nonempty_file(prompt_path):
        return prompt_path
    return _find_nearby_image_prompt_source_path(script_path)

def compact_model_input_document(text: str, *, keep_chars: int | None = None) -> str:
    """精简传给大模型的本地解析文本，降低 token 消耗。

    只删除明显不参与内容理解的噪声：HTML/Markdown 注释、图片链接、URL、页眉页脚、
    页码、重复行、参考文献/索引等尾部材料。正文段落和表格文字尽量保留。
    """
    raw = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    if not raw.strip():
        return ""

    # 去掉 HTML / Markdown 注释、常见解析器控制标记和图片链接。
    raw = re.sub(r"<!--.*?-->", "\n", raw, flags=re.S)
    raw = re.sub(r"(?im)^\s*//\s*(?:TODO|NOTE|注释|comment|remark)[:：].*$", "", raw)
    raw = re.sub(r"(?im)^\s*#\s*(?:TODO|NOTE|注释|comment|remark)[:：].*$", "", raw)
    raw = re.sub(r"!\[[^\]]*\]\([^)]*\)", " ", raw)
    raw = re.sub(r"<img\b[^>]*>", " ", raw, flags=re.I)
    raw = re.sub(r"https?://\S+", " ", raw)

    # 去掉参考文献/索引/版权/致谢等通常不需要送入脚本模型的尾部区块。
    tail_cut = re.search(
        r"(?im)^\s*(?:references|bibliography|selected readings?|further readings?|suggested readings?|index|glossary|acknowledg(?:e)?ments?|版权|参考文献|延伸阅读|推荐阅读|索引|术语表|致谢)\s*$",
        raw,
    )
    if tail_cut and tail_cut.start() > max(1500, len(raw) * 0.45):
        raw = raw[:tail_cut.start()]

    lines = []
    seen_recent = []
    for ln in raw.split("\n"):
        line = re.sub(r"[ \t]+", " ", ln).strip()
        if not line:
            lines.append("")
            continue
        low = line.casefold()
        # 页码、页眉页脚、出版社水印、Markdown 页面分隔符。
        if re.fullmatch(r"(?:page\s*)?\d{1,4}", low):
            continue
        if re.fullmatch(r"[-—–_\s]{3,}", line):
            continue
        if re.search(r"copyright|all rights reserved|mcgraw[-\s]*hill|isbn", low) and len(line) < 160:
            continue
        if re.match(r"^#{1,6}\s*$", line):
            continue
        # 解析器常见坐标/块编号/图片占位。
        if re.match(r"^(?:figure|fig\.|table)\s*\d+(?:[-. ]\d+)?\s*$", low) and len(line) < 30:
            continue
        if re.match(r"^\[?(?:image|figure|table|page|block)[-_ ]?\d+\]?\s*$", low):
            continue

        # 去掉短窗口内重复行，保留第一次出现。
        key = re.sub(r"\W+", "", low)
        if key and len(key) >= 8 and key in seen_recent:
            continue
        seen_recent.append(key)
        if len(seen_recent) > 160:
            seen_recent = seen_recent[-120:]
        lines.append(line)

    compact = "\n".join(lines)
    compact = re.sub(r"\n{3,}", "\n\n", compact).strip()
    if keep_chars is not None:
        try:
            n = max(1000, int(keep_chars))
            compact = compact[:n]
        except Exception:
            pass
    return compact


def truncate_context(text: str, limit: int = SCRIPT_CONTEXT_CHAR_LIMIT) -> str:
    """限制并精简传给大模型的原文长度；集中管理，减少无效 token。"""
    try:
        n = max(1000, int(limit))
    except Exception:
        n = 50000
    return compact_model_input_document(text, keep_chars=n)


def count_pdf_pages_safe(pdf_path: str) -> int:
    """安全读取 PDF 页数；用于 PDF 直传模式下估算更密的分镜数量。"""
    if not pdf_path or not os.path.exists(pdf_path):
        return 0
    try:
        from pypdf import PdfReader
        reader = PdfReader(pdf_path)
        return int(len(reader.pages))
    except Exception:
        return 0



AUTHOR_LABEL_RE = r"(?:by|authors?|edited\\s+by|written\\s+by|作者|著者|主编|编著)"


def _normalize_author_separators(value: str) -> str:
    """统一作者分隔符；只做格式清理，不把多作者压缩成 et al."""
    s = str(value or "").replace("\u00a0", " ")
    s = re.sub(r"\s+", " ", s).strip(" \t-—–:：,，.;；")
    if not s:
        return ""
    s = re.sub(r"\s*(?:;|；|、|/|\\+)\s*", ", ", s)
    s = re.sub(r"\s+(?:and|&|和|与|及)\s+", ", ", s, flags=re.I)
    s = re.sub(r"\s*,\s*", ", ", s)
    s = re.sub(r"(?:,\s*){2,}", ", ", s)
    return s.strip(" ,，;；")


def _clean_pdf_author_candidate(line: str) -> str:
    """清洗从 PDF 封面/title page 固定区域提取出的作者候选行。"""
    s = str(line or "").replace("\u00a0", " ")
    s = re.sub(r"\s+", " ", s).strip(" \t-—–:：,，.;；")
    # 只去掉字段标签，不吞掉作者本身；支持 "By A, B" / "Authors: A; B" / "作者：甲、乙"。
    s = re.sub(rf"^(?:{AUTHOR_LABEL_RE})\s*[：:=]?\s*", "", s, flags=re.I).strip()
    s = re.sub(r"\s*(?:著|编著|主编|编)\s*$", "", s).strip(" ,，;；")
    s = _dedupe_repeated_text(s)
    return _normalize_author_separators(s)


def _looks_like_author_line(line: str, book_title: str = "") -> bool:
    """启发式判断一行 PDF 文本是否像作者名，而不是出版社/目录/版权/营销句。"""
    original = str(line or "").strip()
    s = _clean_pdf_author_candidate(original)
    label_hint = bool(re.search(rf"^(?:{AUTHOR_LABEL_RE})\b", original, flags=re.I))
    if not s or len(s) < 3 or len(s) > 240:
        return False
    norm_title = re.sub(r"[\W_]+", "", str(book_title or "")).lower()
    if norm_title and norm_title in re.sub(r"[\W_]+", "", s).lower():
        return False

    bad = (
        r"(?:copyright|isbn|library|catalog|contents|preface|foreword|chapter|edition|volume|press|publisher|"
        r"university|department|school|institute|rights|reserved|printed|translated|translator|review|glossary|index|mcgraw|pearson|wiley|springer|elsevier|routledge|cengage|prentice|sage|oxford|cambridge|"
        r"corporate|training|programs?|contact|representative|sales|bulk|special\s+sales|permission|permissions|"
        r"request|website|www\.|https?://|e-?mail|email|phone|fax|customer|service|course|courses|"
        r"目录|版权|出版社|出版|译者|前言|序言|章节|第.+版|扫描|下载)"
    )
    if re.search(bad, s, flags=re.I):
        return False
    if "@" in s or re.search(r"\d", s):
        return False
    # 作者行通常不是完整营销/版权句。允许姓名缩写里的句点，但排除普通句子。
    if re.search(r"[!?！？。]", s) or ("." in s and not re.search(r"\b[A-Z]\.", s) and not re.search(r"\bet\s*al\.", s, flags=re.I)):
        return False

    words = re.findall(r"[A-Za-z][A-Za-z'’.-]*", s)
    word_count = len(words)
    if word_count > 32:
        return False

    english_name = bool(re.search(r"\b[A-Z][a-zA-Z'’.-]{1,}\s+(?:[A-Z]\.\s+)?[A-Z][a-zA-Z'’.-]{1,}\b", s))
    capitalized_words = re.findall(r"\b[A-Z][a-zA-Z'’.-]{2,}\b", s)
    has_initial = bool(re.search(r"\b[A-Z]\.\s*(?:[A-Z]\.)?\s*[A-Z][a-zA-Z'’.-]+|\b[A-Z][a-zA-Z'’.-]+\s+[A-Z]\.", s))
    has_joiner = bool(re.search(r"(?:,|，|;|；|\band\b|&|、)", s, flags=re.I))
    cjk_name = bool(re.search(r"[\u4e00-\u9fff]{2,4}(?:\s*[、，,和与及]\s*[\u4e00-\u9fff]{2,4})*", s))
    has_et_al = bool(re.search(r"\bet\s*al\.?\b", s, flags=re.I))

    # 没有字段标签时，避免把书名/副标题误当作者。
    title_like_terms = r"\b(?:principles|science|neuroscience|biology|physiology|psychology|medicine|manual|handbook|textbook|introduction|guide|atlas|methods|clinical|basic|learning|memory|brain|neural|cognitive|systems?)\b"
    original_has_author_separator = bool(re.search(r"(?:,|，|;|；|&|、)", original)) or bool(re.search(r"\s+(?:and|和|与|及)\s+", original)) and len(re.findall(r"\b[A-Z][a-zA-Z'’.-]{2,}\b", original)) >= 3
    if not label_hint and re.search(title_like_terms, s, flags=re.I) and not (has_initial or has_et_al or original_has_author_separator):
        return False

    name_signal = english_name or cjk_name or has_et_al or has_initial or (has_joiner and len(capitalized_words) >= 2) or len(capitalized_words) >= 2
    if label_hint:
        return bool(name_signal)
    return bool(name_signal and (english_name or cjk_name or has_joiner or has_initial or has_et_al))


def _collect_pdf_fixed_region_lines(pdf_path: str, *, max_pages: int = 6) -> list[dict]:
    """从 PDF 前几页的固定书目信息区域读取文本行，保留 page/x/y，用于稳定提取作者。"""
    rows = []
    if not pdf_path or not os.path.exists(pdf_path):
        return rows
    try:
        from pypdf import PdfReader
        reader = PdfReader(pdf_path)
        for page_index, page in enumerate(reader.pages[:max_pages]):
            try:
                w = float(page.mediabox.width or 1)
                h = float(page.mediabox.height or 1)
            except Exception:
                w, h = 1.0, 1.0
            fragments = []
            def visitor_text(text, cm, tm, font_dict, font_size):
                try:
                    t = str(text or "").strip()
                    if not t:
                        return
                    x = float(tm[4]) if tm and len(tm) > 4 else 0.0
                    y = float(tm[5]) if tm and len(tm) > 5 else 0.0
                    if 0.05 * w <= x <= 0.95 * w and 0.14 * h <= y <= 0.86 * h:
                        fragments.append((round(y / 4) * 4, x, t))
                except Exception:
                    return
            try:
                page.extract_text(visitor_text=visitor_text)
            except Exception:
                fragments = []
            if fragments:
                by_y = {}
                for y, x, t in fragments:
                    by_y.setdefault(y, []).append((x, t))
                for y in sorted(by_y.keys(), reverse=True):
                    parts = [t for _x, t in sorted(by_y[y], key=lambda z: z[0])]
                    line = re.sub(r"\s+", " ", " ".join(parts)).strip()
                    if line:
                        rows.append({"page": page_index, "x": min(x for x, _ in by_y[y]), "y": y, "w": w, "h": h, "line": line})
            else:
                try:
                    text = page.extract_text() or ""
                    for i, line in enumerate([ln.strip() for ln in text.splitlines() if ln.strip()]):
                        rows.append({"page": page_index, "x": 0, "y": h * (0.80 - min(i, 25) * 0.025), "w": w, "h": h, "line": line})
                except Exception:
                    continue
    except Exception:
        return rows
    return rows


def _page_looks_like_bibliographic_noise(page_text: str) -> bool:
    """判断页面是否更像版权页/目录页；这些页面不作为作者优先来源。"""
    t = str(page_text or "")
    return bool(re.search(
        r"(copyright|all rights reserved|isbn|library of congress|cataloging|permissions?|printed in|contents|table of contents|"
        r"版权|版权所有|目录|出版社|出版发行|印刷|版次)",
        t,
        flags=re.I,

    ))


def _page_has_titlepage_signal(page_text: str, book_title: str = "") -> bool:

    """判断页面是否像前封面或 title page。"""
    t = str(page_text or "")
    norm_page = re.sub(r"[\W_]+", "", t).lower()
    norm_book = re.sub(r"[\W_]+", "", str(book_title or "")).lower()
    if norm_book and norm_book in norm_page:
        return True
    return bool(re.search(rf"\b(?:{AUTHOR_LABEL_RE})\b|title\s*page|封面|题名页", t, flags=re.I))


def _merge_author_lines_for_display(lines: list[str]) -> str:
    """把同一 title page 上的多行作者合并，保留全部作者，不转换为 et al."""
    cleaned = []
    seen = set()
    for line in lines:
        c = _clean_pdf_author_candidate(line)
        if not c:
            continue
        key = re.sub(r"[\W_]+", "", c).lower()
        if not key or key in seen:
            continue
        seen.add(key)
        cleaned.append(c)
    return _normalize_author_separators(", ".join(cleaned))


def _collect_author_group_around_line(page_rows: list[dict], start_idx: int, book_title: str = "") -> tuple[list[str], bool]:
    """从某一行向后收集连续作者行；返回作者行列表和是否由 By/Author 标签触发。"""
    if start_idx < 0 or start_idx >= len(page_rows):
        return [], False
    line = str(page_rows[start_idx].get("line") or "").strip()
    label_hint = bool(re.search(rf"^(?:{AUTHOR_LABEL_RE})\b\s*[：:=]?", line, flags=re.I))
    group = []

    # 当前行可能是 "By A, B"，也可能只是单独一个作者姓名。
    current_clean = _clean_pdf_author_candidate(line)
    if current_clean and _looks_like_author_line(line, book_title=book_title):
        group.append(current_clean)

    # 若当前行只是 "By" / "Authors"，继续取后面连续作者名。
    for nxt in page_rows[start_idx + 1:start_idx + 8]:
        nxt_line = str(nxt.get("line") or "").strip()
        if not nxt_line:
            continue
        if re.search(r"(?:edition|press|publisher|copyright|isbn|department|university|mcgraw|pearson|wiley|springer|elsevier|routledge|cengage|prentice|sage|出版社|出版|版权|第.+版)", nxt_line, flags=re.I):
            break
        if _looks_like_author_line(nxt_line, book_title=book_title):
            group.append(_clean_pdf_author_candidate(nxt_line))
            continue
        # 已经拿到作者后，遇到非作者行就停止，避免串到出版社或副标题。
        if group:
            break
        # 标签触发但第一行为空时，允许跳过一行短装饰/空标签。
        if not label_hint:
            break

    return group, label_hint


def extract_book_author_from_pdf_fixed_region(pdf_path: str, book_title: str = "", logger=None) -> str:
    """优先从 PDF 前封面 / title page 提取完整作者列表；失败时返回空，不写死任何默认作者。"""
    try:
        max_pages = int(os.environ.get("QUANLAN_AUTHOR_SCAN_PAGES", "8"))
    except Exception:
        max_pages = 8
    rows = _collect_pdf_fixed_region_lines(pdf_path, max_pages=max_pages)
    if not rows:
        return ""

    pages: dict[int, list[dict]] = {}
    for row in rows:
        pages.setdefault(int(row.get("page") or 0), []).append(row)

    candidates = []
    norm_book = re.sub(r"[\W_]+", "", str(book_title or "")).lower()
    for page, page_rows in sorted(pages.items()):
        # 视觉顺序：从页面上方到下方。
        page_rows = sorted(page_rows, key=lambda r: (-float(r.get("y") or 0), float(r.get("x") or 0)))
        page_text = "\n".join(str(r.get("line") or "") for r in page_rows)
        bibliographic_noise = _page_looks_like_bibliographic_noise(page_text)
        titlepage_signal = _page_has_titlepage_signal(page_text, book_title=book_title)

        for idx, row in enumerate(page_rows):
            group, label_hint = _collect_author_group_around_line(page_rows, idx, book_title=book_title)
            if not group:
                continue
            author = _merge_author_lines_for_display(group)
            if not author or not _looks_like_author_line(author, book_title=book_title):
                continue

            y = float(row.get("y") or 0)
            h = float(row.get("h") or 1)
            y_ratio = y / max(1.0, h)
            score = 0
            # 明确优先：封面和 title page，而不是版权页。
            score += max(0, 20 - page * 3)
            if titlepage_signal:
                score += 12
            if bibliographic_noise:
                score -= 18
            if label_hint:
                score += 14
            if norm_book and norm_book in re.sub(r"[\W_]+", "", page_text).lower():
                score += 10
            if 0.22 <= y_ratio <= 0.78:
                score += 4
            if len(group) >= 2:
                score += min(8, len(group) * 2)
            if re.search(r"(?:,|，|;|；|\band\b|&|、)", author, flags=re.I):
                score += 3
            if re.search(r"\bet\s*al\.?\b", author, flags=re.I):
                score -= 3  # 不是禁止；只是如果同页有完整名单，优先完整名单。
            candidates.append((score, -page, -abs(y_ratio - 0.50), author))

    if not candidates:
        # 兜底：只在前两页里找最高质量的单行作者，仍避免版权/目录页。
        for page, page_rows in sorted(pages.items()):
            if page > 1:
                break
            page_text = "\n".join(str(r.get("line") or "") for r in page_rows)
            if _page_looks_like_bibliographic_noise(page_text):
                continue
            for row in page_rows:
                line = str(row.get("line") or "").strip()
                if _looks_like_author_line(line, book_title=book_title):
                    author = _clean_pdf_author_candidate(line)
                    candidates.append((1, -page, 0, author))

    if not candidates:
        return ""

    candidates.sort(reverse=True)
    author = _merge_author_lines_for_display([candidates[0][3]])
    if not _looks_like_author_line(author, book_title=book_title):
        return ""
    if logger:
        logger(f"👤 已从 PDF 前封面/title page 提取作者：{author}")
    return author



def _normalize_cover_home_cache_book_fields(book_title: str, book_title_cn: str, version_text: str, author_line: str) -> tuple[str, str, str, str]:
    """封面/首页缓存字段规范化：Kandel 书籍使用固定中文书名、版本、作者简写。"""
    bt = str(book_title or "").strip()
    btc = str(book_title_cn or "").strip()
    ver = str(version_text or "").strip()
    author = str(author_line or "").strip()
    joined = " ".join([bt, btc, ver, author])
    if re.search(r"principles\s+of\s+neural\s+science|神经科学原理", joined, flags=re.I):
        bt = "Principles of Neural Science"
        btc = "神经科学原理"
        if not ver:
            ver = "第六版"
        if not author:
            author = "ERIC R. KANDEL 等人合著"
    return bt, btc, ver, author

def save_cover_home_metadata_cache(ch_dir: str, *, book_title: str = "", book_title_cn: str = "", version_text: str = "", author_line: str = "", chapter_number: str = "", chapter_title: str = "", chapter_title_cn: str = "", chapter_title_en: str = "") -> str:
    """保存封面/首页后处理用元信息，供后续图片重绘时稳定读取。

    科学著作封面必须同时保留中文章名与英文章名。旧缓存如果缺少 Chapter Title EN、
    或把中文章名误写到英文位置，会被自动刷新，避免封面继续沿用旧错误。
    """
    if not ch_dir:
        return ""
    path = os.path.join(ch_dir, "0_封面首页元信息.txt")

    book_title, book_title_cn, version_text, author_line = _normalize_cover_home_cache_book_fields(book_title, book_title_cn, version_text, author_line)

    clean_en_func = globals().get("clean_chapter_title_english_text")
    choose_en_func = globals().get("choose_complete_chapter_title_english_text")
    clean_cn_func = globals().get("clean_chapter_title_translation_text")
    contains_cjk = globals().get("contains_cjk_text")
    try:
        if callable(choose_en_func):
            chapter_title_en_value = choose_en_func(chapter_title_en, chapter_title)
        else:
            chapter_title_en_value = clean_en_func(chapter_title_en or chapter_title, fallback=chapter_title or "") if callable(clean_en_func) else str(chapter_title_en or chapter_title or "").strip()
    except Exception:
        chapter_title_en_value = str(chapter_title_en or chapter_title or "").strip()
    try:
        chapter_title_cn_value = clean_cn_func(chapter_title_cn, fallback="") if callable(clean_cn_func) else str(chapter_title_cn or "").strip()
    except Exception:
        chapter_title_cn_value = str(chapter_title_cn or "").strip()

    def _cache_has_complete_required_fields() -> bool:
        """已有 0_封面首页元信息.txt 是封面权威文件。

        只要字段完整且章节中英文名合法，就保留用户/历史缓存内容；不要因为文件夹名、
        短视频小标题或本轮翻译结果不同而覆盖它。字段缺失或明显污染时才重写。
        """
        if not should_reuse_existing_file(path, min_bytes=20):
            return False
        try:
            old = read_text_file(path)
        except Exception:
            return False
        required = [
            "Book Title", "Book Title CN", "Version", "Author",
            "Chapter Number", "Chapter Title EN", "Chapter Title CN",
        ]
        values = {key: _read_simple_kv_value(old, key) for key in required}
        artifact_check = globals().get("_is_cover_home_workflow_title_artifact")
        old_en = values.get("Chapter Title EN", "")
        old_cn = values.get("Chapter Title CN", "")
        if callable(artifact_check) and (artifact_check(old_en) or artifact_check(old_cn)):
            return False
        if not all(str(values.get(key, "")).strip() for key in required):
            return False
        if callable(contains_cjk) and contains_cjk(old_en):
            return False
        if callable(contains_cjk) and not contains_cjk(old_cn):
            return False
        return True

    def _cache_has_both_titles() -> bool:
        return _cache_has_complete_required_fields()

    if _cache_has_both_titles():
        return path

    lines = [
        "封面页/首页元信息：",
        f"Book Title: {book_title}",
        f"Book Title CN: {book_title_cn}",
        f"Version: {version_text}",
        f"Author: {author_line}",
        f"Chapter Number: {chapter_number}",
        f"Chapter Title: {chapter_title_en_value or chapter_title}",
        f"Chapter Title EN: {chapter_title_en_value or chapter_title}",
        f"Chapter Title CN: {chapter_title_cn_value or chapter_title_cn}",
    ]
    write_text_file(path, "\n".join(lines).rstrip() + "\n")
    return path

def estimate_dynamic_image_plan(source_text: str, chapter_title: str = "", chapter_number: str = "", source_pdf_path: str = "") -> dict:
    """返回章节配图上下文；不按 PDF 页数凑图，但脚本阶段必须按 3~8 秒镜头规划。"""
    raw = str(source_text or "").replace("\r\n", "\n").replace("\r", "\n")
    paras = [ln.strip() for ln in raw.split("\n") if ln.strip()]
    cjk_chars = len(re.findall(r"[\u4e00-\u9fff]", raw))
    en_words = len(re.findall(r"[A-Za-z]+", raw))
    pdf_page_count = count_pdf_pages_safe(source_pdf_path)
    return {
        "chapter_number": str(chapter_number or "").strip(),
        "chapter_title": str(chapter_title or "").strip(),
        "paragraph_count": len(paras),
        "cjk_chars": cjk_chars,
        "en_words": en_words,
        "pdf_page_count": pdf_page_count,
        "planning_mode": "llm_3_8s_shot_level_script_design",
    }


def build_dynamic_image_count_instruction(plan: dict) -> str:
    pdf_page_count = int((plan or {}).get("pdf_page_count") or 0)
    pdf_hint = f"本章章节 PDF 约 {pdf_page_count} 页；此信息仅供模型理解章节体量，不得用于按页数凑图。\n" if pdf_page_count else ""
    return (
        "【3~8 秒镜头制：要求 Gemini / 大模型在脚本生成阶段同步设计】\n"
        "程序不再用 LRC 的时间戳、PDF 页数或旧的自然段均分方式切画面；LRC 只负责最终字幕时间戳。\n"
        "脚本生成模型必须先把 Part One 旁白在内部规划成连续镜头，再输出 Part Two；不能先写一整段长旁白、再只给少量 B 图。\n"
        "每个非封面镜头必须对应 3~8 秒可朗读台词，并同步生成一张强相关医学配图；按中文科普口播约 5–6 个汉字/秒估算。\n"
        "每个镜头只能承载一个清晰科学命题：一个对象、一个机制、一个证据、一个对比、一个步骤、一个因果关系或一个层级关系。\n"
        "B 系列必须按 3~8 秒/镜头展开主体内容：超过 8 秒必须拆分；短于 3 秒且语义未变化可与相邻句合并，但合并后不得超过 8 秒。\n"
        "如果一句或一段包含两个以上机制/证据/对比/步骤，即使不足 8 秒，也必须按语义焦点拆成多张 B 图。\n"
        "不要预设固定总图数，也不要凑图；总图数应由旁白总时长按 3~8 秒/镜头自然展开，并由语义焦点校正。\n"
        + pdf_hint +
        "禁止使用 30 秒 LRC 间隔来生成或切分镜头；30 秒只用于 LRC 时间戳留白，不代表镜头时长；禁止输出与台词无关的过渡图、空白 B 页、泛医学壁纸或科技氛围图。\n"
        "A1 是封面无口播；A2 对应章节提要句；A01/A02 只复用 A1 母图裁切；B 系列从正文第一组语义开始按 3~8 秒/镜头连续编号；C 对应结尾总结/下一章标题级预告/关注语，也按 3~8 秒可朗读台词规划。"
    )


def clean_script_text_for_output(script_text: str) -> str:
    """保存脚本与生成 LRC 前的统一保守清洗链。"""
    return sanitize_final_chinese_logic_and_professional_expression(
        sanitize_sentence_clarity_and_redundancy(
            sanitize_scientific_chinese_style(
                apply_professional_terminology_cleanup(script_text or "")
            )
        )
    )


def ensure_lrc_for_existing_script(script_path: str, logger=None) -> str:
    """脚本已存在时，先确保独立台词/绘图提示词文件存在，再从台词文件重建 LRC。"""
    lrc_path = os.path.splitext(script_path)[0] + ".lrc"
    if not is_nonempty_file(script_path):
        return lrc_path
    try:
        script_text = read_text_file(script_path)
        voiceover_path = get_voiceover_text_path(script_path)
        prompt_path = get_image_prompt_text_path(script_path)
        marker_map_path = get_lrc_image_marker_map_path(script_path)
        if (
            resume_skip_existing_enabled()
            and not resume_force_rebuild_enabled()
            and is_nonempty_file(lrc_path, min_bytes=20)
            and is_nonempty_file(voiceover_path, min_bytes=20)
            and is_nonempty_file(prompt_path, min_bytes=20)
            and (unified_intermediate_files_enabled() or is_nonempty_file(marker_map_path, min_bytes=5))
        ):
            if logger:
                logger(f"♻️ 已存在 LRC/台词/绘图提示词/配图锚点，跳过重建：{os.path.basename(lrc_path)}")
            return lrc_path
        if not is_nonempty_file(voiceover_path) or not is_nonempty_file(prompt_path):
            voiceover_text, image_prompt_text = split_final_script_to_voiceover_and_prompts(script_text)
            if voiceover_text and (not is_nonempty_file(voiceover_path) or not is_nonempty_file(get_voiceover_script_alias_path(script_path))):
                write_separated_voiceover_files(script_path, voiceover_text)
            if image_prompt_text and (not is_nonempty_file(prompt_path) or not is_nonempty_file(get_drawing_script_alias_path(script_path))):
                write_separated_drawing_files(script_path, image_prompt_text)
        voiceover_source = read_text_file(voiceover_path) if is_nonempty_file(voiceover_path) else script_text
        prompt_source = read_text_file(get_image_prompt_text_path(script_path)) if is_nonempty_file(get_image_prompt_text_path(script_path)) else script_text
        raw_backup_path = os.path.splitext(script_path)[0] + "_完整脚本原稿.txt"
        if not has_lrc_image_marker(voiceover_source) and is_nonempty_file(raw_backup_path):
            raw_text = read_text_file(raw_backup_path)
            rebuilt_voiceover, rebuilt_prompts = split_initial_script_to_two_small_files(raw_text, logger=logger)
            if rebuilt_voiceover.strip():
                voiceover_source = purge_visual_prompt_contamination_from_voiceover(rebuilt_voiceover)
                write_separated_voiceover_files(script_path, voiceover_source)
                write_text_file(script_path, voiceover_source)
            if rebuilt_prompts.strip() and not is_nonempty_file(get_image_prompt_text_path(script_path)):
                prompt_source = rebuilt_prompts
                write_separated_drawing_files(script_path, rebuilt_prompts)
        lrc_text = generate_lrc_text(voiceover_source, interval_seconds=LRC_INTERVAL_SECONDS, image_prompt_text=prompt_source)
        write_text_file(lrc_path, lrc_text)
        write_lrc_image_marker_map(script_path, voiceover_source)
        if logger:
            logger(f"✅ 已从独立台词文件重建 LRC：{os.path.basename(lrc_path)}")
    except Exception as e:
        if logger:
            logger(f"⚠️ 已有脚本 LRC 更新失败：{str(e)[:120]}")
    return lrc_path


def _find_existing_image_for_prompt(images_dir: str, prompt_name: str) -> str:
    """在配图目录及其子目录中查找已经存在的指定图片，兼容网页手动下载/拖入子文件夹的情况。"""
    try:
        if not images_dir or not os.path.isdir(images_dir) or not prompt_name:
            return ""
        target_names = {
            f"{prompt_name}.png", f"{prompt_name}.jpg", f"{prompt_name}.jpeg", f"{prompt_name}.webp",
        }
        # 兼容用户手动保存时把中文页名改成英文别名。
        low = str(prompt_name).lower()
        if re.search(r"(?:^|[^a-z])a1(?:[^a-z]|$)|封面", low, flags=re.I):
            target_names.update({"A1.png", "A1_cover.png", "A1_封面页.png", "cover.png", "封面页.png"})
        if re.search(r"(?:^|[^a-z])a2(?:[^a-z]|$)|首页", low, flags=re.I):
            target_names.update({"A2.png", "A2_home.png", "A2_首页.png", "home.png", "首页.png"})
        if re.search(r"(?:^|[^a-z])c(?:[^a-z]|$)|品牌|尾页|结束", low, flags=re.I):
            target_names.update({"C.png", "C_brand.png", "C_品牌页.png", "brand.png", "品牌页.png"})

        exact_hits = []
        fuzzy_hits = []
        for cur, dirs, files in os.walk(images_dir):
            parts = set(os.path.normpath(cur).split(os.sep))
            if "_raw" in parts:
                dirs[:] = []
                continue
            dirs[:] = [d for d in dirs if not d.startswith('.') and d != '_raw']
            for name in files:
                if not name or name.startswith('.'):
                    continue
                ext = os.path.splitext(name)[1].lower()
                if ext not in SUPPORTED_POSTPROCESS_IMAGE_EXTS:
                    continue
                path = os.path.join(cur, name)
                if not is_nonempty_file(path, min_bytes=1000):
                    continue
                if name in target_names:
                    exact_hits.append(path)
                else:
                    base = os.path.splitext(name)[0].lower()
                    # A/B/C 页名的兜底匹配，避免手动保存时多了空格、编号或英文后缀。
                    if re.search(r"(?:^|[^a-z])a1(?:[^a-z]|$)|封面", low, flags=re.I) and re.search(r"(?:^|[^a-z])a1(?:[^a-z]|$)|cover|封面", base, flags=re.I):
                        fuzzy_hits.append(path)
                    elif re.search(r"(?:^|[^a-z])a2(?:[^a-z]|$)|首页", low, flags=re.I) and re.search(r"(?:^|[^a-z])a2(?:[^a-z]|$)|home|首页", base, flags=re.I):
                        fuzzy_hits.append(path)
                    elif re.search(r"(?:^|[^a-z])c(?:[^a-z]|$)|品牌|尾页|结束", low, flags=re.I) and re.search(r"(?:^|[^a-z])c(?:[^a-z]|$)|brand|ending|尾页|品牌", base, flags=re.I):
                        fuzzy_hits.append(path)
        hits = exact_hits or fuzzy_hits
        if not hits:
            return ""
        # 离 images_dir 最近、路径最短的优先。
        hits.sort(key=lambda x: (len(os.path.relpath(x, images_dir).split(os.sep)), os.path.relpath(x, images_dir).lower()))
        return hits[0]
    except Exception:
        return ""



def summarize_image_resume_state(script_path: str, images_dir: str, logger=None):
    """根据已有脚本和图片，计算配图断点续跑状态。优先从独立绘图提示词文件读取。"""
    prompt_source_path = get_preferred_prompt_source_path(script_path)
    if not is_nonempty_file(prompt_source_path):
        if logger:
            logger("⚠️ 找不到可用脚本或独立绘图提示词文件，无法提取配图提示词。")
        return [], [], 0
    prompts = ScriptParser.extract_image_prompts(read_text_file(prompt_source_path), logger)
    os.makedirs(images_dir, exist_ok=True)
    pending = []
    done_count = 0
    for p_name, p_text in prompts:
        img_save_path = os.path.join(images_dir, f"{p_name}.png")
        existing_path = img_save_path if is_nonempty_file(img_save_path, min_bytes=1000) else _find_existing_image_for_prompt(images_dir, p_name)
        if existing_path and is_nonempty_file(existing_path, min_bytes=1000):
            # v8.0 断点续作：默认只要目标图片已经存在，就视为完成，不再因为 Prompt
            # 指纹缺失/不一致而重绘，也不重新后处理，避免已有文件被重复消耗或覆盖。
            if resume_skip_existing_enabled() and not resume_force_rebuild_enabled():
                if resume_strict_image_prompt_match_enabled() and not image_prompt_sidecar_matches(existing_path, p_name, p_text):
                    pending.append((p_name, p_text, img_save_path))
                    if logger:
                        logger(f"♻️ {p_name} 已有图片但 Prompt 指纹不匹配；因已开启严格匹配，将重新生成。")
                    continue
                if resume_touch_existing_images_enabled():
                    postprocess_generated_image(existing_path, p_text, logger=logger, prompt_name=p_name)
                done_count += 1
                if logger and os.path.abspath(existing_path) != os.path.abspath(img_save_path):
                    logger(f"📁 已在子目录发现已有图片并跳过重做：{os.path.relpath(existing_path, images_dir)}")
                continue

            if not image_prompt_sidecar_matches(existing_path, p_name, p_text):
                pending.append((p_name, p_text, img_save_path))
                if logger:
                    logger(f"♻️ {p_name} 已有图片但缺少/不匹配当前 API Prompt 指纹，将按新版提示词重新生成。")
                continue
            postprocess_generated_image(existing_path, p_text, logger=logger, prompt_name=p_name)
            done_count += 1
            if logger and os.path.abspath(existing_path) != os.path.abspath(img_save_path):
                logger(f"📁 已在子目录发现并后处理已有图片：{os.path.relpath(existing_path, images_dir)}")
        else:
            pending.append((p_name, p_text, img_save_path))
    if logger and prompts:
        logger(f"🎨 配图状态：共 {len(prompts)} 张，已完成 {done_count} 张，待生成 {len(pending)} 张。")
    return prompts, pending, done_count


def _sync_cover_home_metadata_to_images_dir(script_path: str, images_dir: str, logger=None) -> str:
    """把章节根目录的封面/首页元信息同步到配图目录，确保 A1/A2 后处理一定能就近读取。"""
    try:
        if not script_path or not images_dir:
            return ""
        ch_dir = os.path.dirname(os.path.abspath(script_path))
        src = _find_cover_home_metadata_file_near_dir(ch_dir, max_depth=2)
        if not is_nonempty_file(src):
            return ""
        os.makedirs(images_dir, exist_ok=True)
        dst = os.path.join(images_dir, "0_封面首页元信息.txt")
        try:
            if os.path.abspath(src) != os.path.abspath(dst):
                src_txt = read_text_file(src)
                if src_txt and (not os.path.exists(dst) or read_text_file(dst) != src_txt):
                    write_text_file(dst, src_txt)
                    if logger:
                        logger("📌 已同步封面/首页元信息到配图目录，供 A1/A2 后处理就近读取。")
            return dst
        except Exception:
            return src
    except Exception:
        return ""



def ensure_all_generated_images_postprocessed(script_path: str, images_dir: str, logger=None) -> dict:
    """对已生成图片再做一遍幂等后处理，保证断点续跑/网页手动图也能统一盖章。"""
    prompt_source_path = get_preferred_prompt_source_path(script_path)
    if not images_dir or not os.path.isdir(images_dir):
        return {"ok": 0, "failed": 0, "skipped": 0}
    _sync_cover_home_metadata_to_images_dir(script_path, images_dir, logger=logger)
    result = postprocess_image_folder(
        images_dir,
        role="auto",
        prompt_file=prompt_source_path if is_nonempty_file(prompt_source_path) else "",
        recursive=True,
        logger=logger,
    )
    return result


def infer_resume_status(md_path: str, script_path: str, images_dir: str, logger=None) -> dict:
    """汇总当前章节的断点状态，用于日志提示和自动跳步。v113 不再依赖 Markdown 解析结果。"""
    ch_dir = os.path.dirname(os.path.abspath(script_path)) if script_path else ""
    chapter_pdf_path = os.path.join(ch_dir, "00_章节原文_PDF直传模型.pdf") if ch_dir else ""
    status = {
        "chapter_pdf": is_nonempty_file(chapter_pdf_path, min_bytes=1000),
        "legacy_md": is_nonempty_file(md_path),
        "script": is_nonempty_file(script_path),
        "lrc": is_nonempty_file(os.path.splitext(script_path)[0] + ".lrc"),
        "images_total": 0,
        "images_done": 0,
        "images_pending": 0,
    }
    if status["script"]:
        try:
            prompts, pending, done_count = summarize_image_resume_state(script_path, images_dir, logger=None)
            status["images_total"] = len(prompts)
            status["images_done"] = done_count
            status["images_pending"] = len(pending)
        except Exception:
            pass
    if logger:
        logger(
            "📌 当前文件状态："
            f"章节PDF={'已准备' if status['chapter_pdf'] else '未准备'}，"
            f"脚本={'已完成' if status['script'] else '未完成'}，"
            f"LRC={'已完成' if status['lrc'] else '未完成'}，"
            f"配图={status['images_done']}/{status['images_total']}"
        )
    return status


def _normalize_chapter_dir_key(text: str) -> str:
    """把目录名/章节标题标准化，用于识别旧版本输出目录。"""
    s = unicodedata.normalize("NFKC", str(text or "")).lower()
    s = re.sub(r"[\s_\-—–:：、,，.．/\\()（）\[\]【】'\"“”‘’]+", "", s)
    return s.strip()


